@click.argument('input_file', type=click.Path(exists=True))
@click.option('-o', '--output', required=True, help='Output PPT file path')
@click.option('--security', type=click.Choice(['PUBLIC', 'INTERNAL', 'CONFIDENTIAL']), 
              default='INTERNAL', help='Security level')
@click.option('--theme', default='default', help='Presentation theme')
@click.option('--verbose', is_flag=True, help='Verbose output')
def generate(input_file, output, security, theme, verbose):
    """Generate PPT from JSON input"""

    if verbose:
        logger.add(lambda msg: click.echo(msg, err=True))

    click.echo(f"🚀 Generating presentation...")
    click.echo(f"   Input: {input_file}")
    click.echo(f"   Output: {output}")
    click.echo(f"   Security: {security}")

    agent = SlideGenAgent()
    success = agent.process(input_file, output, security, theme)

    if success:
        click.echo(f"✅ Success! Presentation saved to {output}")
    else:
        click.echo(f"❌ Failed to generate presentation", err=True)
        raise click.Abort()


